# ══════════════════════════════════════════════════════════════
#  輔助：標籤列（label + widget）
# ══════════════════════════════════════════════════════════════
def _field_row(label: str, widget: QWidget, tip: str = "") -> QHBoxLayout:
    lbl = QLabel(label)
    lbl.setFixedWidth(72)
    lbl.setStyleSheet(f"color:{C['sub']}; font-size:12.5px; background:transparent;")
    if tip:
        lbl.setToolTip(tip)
        widget.setToolTip(tip)
    row = QHBoxLayout()
    row.setSpacing(10)
    row.setContentsMargins(0, 0, 0, 0)
    row.addWidget(lbl)
    row.addWidget(widget, 1)
    return row


