class StatusBadge(QLabel):
    _STYLES = {
        "idle":    ("待機",    C['sub'],   C['dim']),
        "running": ("● 執行中", "#FFFFFF", C['accent2'] + "CC"),
        "error":   ("● 已中斷", "#FFFFFF", C['danger']  + "AA"),
    }

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setAlignment(Qt.AlignmentFlag.AlignCenter)
        self.setFixedSize(86, 26)
        self.set_state("idle")

    def set_state(self, state: str):
        text, fg, bg = self._STYLES.get(state, self._STYLES["idle"])
        self.setText(text)
        self.setStyleSheet(
            f"color:{fg}; background:{bg}; border-radius:12px;"
            f" font-size:12px; font-weight:700; border:none;"
        )


# ══════════════════════════════════════════════════════════════
#  進程監控（QObject + QTimer，訊號安全派發）
# ══════════════════════════════════════════════════════════════
class ProcWatcher(QObject):
    finished = pyqtSignal(int)   # 結束碼（任何退出都會觸發）

    def __init__(self, proc: subprocess.Popen, parent: QObject = None):
        super().__init__(parent)
        self._proc   = proc
        self._active = True
        self._timer  = QTimer(self)
        self._timer.setInterval(500)
        self._timer.timeout.connect(self._poll)
        self._timer.start()

    def _poll(self):
        if not self._active:
            return
        try:
            code = self._proc.poll()
        except Exception:
            code = -1
        if code is not None:
            self._active = False
            self._timer.stop()
            self.finished.emit(code)

    def stop(self):
        self._active = False
        self._timer.stop()


